# Combine the MAGs
cat binning/final_MAGs/mealworm/*.fasta > MAG_abundance/Mealworm_MAGs_combined.fasta
cat binning/final_MAGs/superworm/*.fasta > MAG_abundance/Superworm_MAGs_combined.fasta 

# Change directory
cd MAG_abundance/

# Build bowtie2 databases
bowtie2-build --threads 24 Mealworm_MAGs_combined.fasta mealworm_MAGs_database
bowtie2-build --threads 24 Superworm_MAGs_combined.fasta superworm_MAGs_database

