cd ../

# Get overall mapping rates
grep 'overall' MAG_abundance/*.txt > MAG_abundance/mapping_rate.txt

# Get sample and MAG names
ls -1 MAG_abundance/ | grep 'Mealworm' | grep 'bam' | sed 's/\.bam//' > MAG_abundance/mealworm_sample_names.txt
ls -1 MAG_abundance/ | grep 'Superworm' | grep 'bam' | sed 's/\.bam//' > MAG_abundance/superworm_sample_names.txt
grep '>' MAG_abundance/Mealworm_MAGs_combined.fasta | sed 's/>//' | sed 's/_contig_/\t/' | cut -f1,1 | sort -u > MAG_abundance/mealworm_MAG_names.txt
