# Get MAG abundances
cd MAG_abundance/
perl ../scripts/getAbundance_mealworm.pl
perl ../scripts/getAbundance_superworm.pl
perl ../scripts/getAbundance_mealworm_2.pl
perl ../scripts/getAbundance_superworm_2.pl
cd ../